const raw = $input.first().json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const clean = text.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
let datos = {};
try { datos = JSON.parse(clean); } catch(e) { datos = {}; }
if (datos.placa) datos.placa = datos.placa.toUpperCase().replace(/\s/g, '');
if (datos.vin) datos.vin = datos.vin.toUpperCase().replace(/\s/g, '');
if (datos.cedula_nit) datos.cedula_nit = datos.cedula_nit.replace(/\D/g, '');
return [{ json: { datos } }];
